class Solution:
    def minStartingIndex(self, s: str, pattern: str) -> int:
        n = len(s)
        m = len(pattern)
        diff = 0
        for i in range(m):
            if s[i] != pattern[i]:
                diff += 1
        if diff > 1:
            return -1
        min_index = n
        for i in range(n - m + 1):
            j = 0
            while j < m:
                if s[i + j] != pattern[j]:
                    diff += 1
                j += 1
            if diff <= 1:
                min_index = min(min_index, i)
            diff = 0
        return min_index if min_index != n else -1
